  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({ programEncounter });
  const moment = imports.moment;

  // Basic guard: only if still active in program
  if (programEncounter.programEnrolment.programExitDateTime) {
    return scheduleBuilder.getAll();
  }

  const status = programEncounter.getObservationReadableValue('Nutritional status of child') || programEncounter.getObservationReadableValue('Current nutritional status according to weight and age');

  // Determine earliest and latest dates based on status
  let earliestDate = null;
  let latestDate = null;

  if (status === 'SAM') {
    earliestDate = moment(programEncounter.encounterDateTime).add(7, 'days').startOf('day').toDate();
    latestDate = moment(earliestDate).add(7, 'days').endOf('day').toDate(); // ~1 week window
  } else if (status === 'MAM') {
    earliestDate = moment(programEncounter.encounterDateTime).add(14, 'days').startOf('day').toDate();
    latestDate = moment(earliestDate).add(14, 'days').endOf('day').toDate(); // ~2 weeks window
  } else if (status === 'Normal') {
    earliestDate = moment(programEncounter.encounterDateTime).add(30, 'days').startOf('day').toDate();
    latestDate = moment(earliestDate).add(7, 'days').endOf('day').toDate(); // ~1 week window
  } else {
    // status not recognized - do not schedule
    return scheduleBuilder.getAll();
  }

  // Avoid duplicate scheduling: if a Child Followup is already scheduled for the same earliestDate, skip
  const encounterTypeName = 'Child Followup';
  const isAlreadyScheduled = programEncounter.programEnrolment.encounters.some(enc =>
    enc.encounterType.name === encounterTypeName &&
    enc.voided === false &&
    moment(enc.earliestVisitDateTime).isSame(moment(earliestDate), 'day')
  );

  if (!isAlreadyScheduled) {
    scheduleBuilder.add({
      name: 'Child Followup',
      encounterType: encounterTypeName,
      earliestDate,
