  const existingFollowUps = programEncounter.programEnrolment.getEncountersOfType('ANC - Follow Up', false) || [];
  const isAlreadyScheduled = existingFollowUps.some((enc) =>
    enc.earliestVisitDateTime ? moment(enc.earliestVisitDateTime).isSame(earliestDate, 'day') : false
  );

  // If no conflicting follow-up exists, add the follow-up schedule
  if (!isAlreadyScheduled) {
    scheduleBuilder.add({
      name: 'ANC - Follow Up',
      encounterType: 'ANC - Follow Up',
      earliestDate,
      maxDate
    });
  }

  return scheduleBuilder.getAll();
